"use client";

import { useState } from 'react';
import { motion } from 'framer-motion';
import {
  User, Phone, Mail, Calendar, Droplets, AlertTriangle,
  MapPin, Shield, Edit2, Save, X, Plus, Trash2, Heart,
  Lock, Camera, CheckCircle, Users,
} from 'lucide-react';
import DashboardLayout from '@/components/layout/DashboardLayout';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarImage, AvatarFallback } from '@/components/ui/avatar';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter,
} from '@/components/ui/dialog';
import { useAuthStore } from '@/store';
import { useToast } from '@/hooks/use-toast';
import { usePharmacyStore, DeliveryAddress } from '@/store/pharmacyStore';

const bloodTypes = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

type AddressFieldKey = keyof Omit<DeliveryAddress, 'id' | 'isDefault'>;

const addressFields: { label: string; key: AddressFieldKey; placeholder: string }[] = [
  { label: 'Full Name *', key: 'fullName', placeholder: 'Maria Santos' },
  { label: 'Mobile Number *', key: 'mobile', placeholder: '09xx-xxx-xxxx' },
  { label: 'House/Unit No.', key: 'houseUnit', placeholder: '123' },
  { label: 'Street *', key: 'street', placeholder: 'Makati Avenue' },
  { label: 'Barangay', key: 'barangay', placeholder: 'Bel-Air' },
  { label: 'City / Municipality *', key: 'city', placeholder: 'Makati City' },
  { label: 'Province', key: 'province', placeholder: 'Metro Manila' },
  { label: 'ZIP Code', key: 'zipCode', placeholder: '1209' },
  { label: 'Delivery Notes', key: 'notes', placeholder: 'Near the gate, blue mailbox' },
];
interface FamilyMember {
  id: string;
  name: string;
  relationship: string;
  dob: string;
  bloodType: string;
}

const mockFamilyMembers: FamilyMember[] = [
  { id: 'fm-1', name: 'Roberto Santos', relationship: 'Husband', dob: '1988-03-12', bloodType: 'A+' },
  { id: 'fm-2', name: 'Sofia Santos', relationship: 'Daughter', dob: '2015-07-22', bloodType: 'O+' },
];

export default function ProfilePage() {
  const { user } = useAuthStore();
  const { toast } = useToast();
  const { savedAddresses, addAddress } = usePharmacyStore();

  const [editingSection, setEditingSection] = useState<string | null>(null);
  const [addAddressOpen, setAddAddressOpen] = useState(false);
  const [addFamilyOpen, setAddFamilyOpen] = useState(false);

  // Profile form state
  const [profile, setProfile] = useState({
    name: user?.name || 'Maria Santos',
    phone: '+63 917 123 4567',
    email: user?.email || 'maria.santos@email.com',
    dob: '1990-05-15',
    gender: 'female',
    bloodType: 'O+',
    allergies: 'Penicillin',
    emergencyContact: '+63 917 987 6543',
    emergencyName: 'Roberto Santos',
    hmoProvider: 'PhilHealth / Maxicare',
    hmoNumber: 'MXC-2024-001234',
  });

  const [newAddress, setNewAddress] = useState<Partial<DeliveryAddress>>({
    fullName: user?.name || '',
    mobile: '',
    houseUnit: '',
    street: '',
    barangay: '',
    city: '',
    province: 'Metro Manila',
    zipCode: '',
    notes: '',
  });

  const [familyMembers] = useState<FamilyMember[]>(mockFamilyMembers);

  const handleSave = (section: string) => {
    toast({ title: 'Profile updated', description: `${section} saved successfully.` });
    setEditingSection(null);
  };

  const handleAddAddress = () => {
    if (!newAddress.fullName || !newAddress.street || !newAddress.city) {
      toast({ title: 'Missing fields', description: 'Please fill in required address fields.', variant: 'destructive' });
      return;
    }
    addAddress(newAddress as Omit<DeliveryAddress, 'id'>);
    toast({ title: 'Address added!', description: 'New delivery address saved.' });
    setAddAddressOpen(false);
    setNewAddress({
      fullName: user?.name || '',
      mobile: '',
      houseUnit: '',
      street: '',
      barangay: '',
      city: '',
      province: 'Metro Manila',
      zipCode: '',
      notes: '',
    });
  };

  const getInitials = (name: string) => {
    const cleaned = name.trim();
    if (!cleaned) return 'NA';
    return cleaned
      .split(' ')
      .map((n) => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  const allergyList = profile.allergies
    .split(',')
    .map((a) => a.trim())
    .filter(Boolean);

  return (
    <DashboardLayout>
      <div className="max-w-3xl mx-auto space-y-6 pb-10">
        {/* Page header */}
        <div>
          <h1 className="text-2xl font-bold text-foreground">My Profile</h1>
          <p className="text-muted-foreground text-sm mt-0.5">Manage your personal info, health details, and preferences</p>
        </div>

        <Tabs defaultValue="personal" className="space-y-4">
          <TabsList className="grid w-full grid-cols-4">
            <TabsTrigger value="personal">Personal</TabsTrigger>
            <TabsTrigger value="health">Health Info</TabsTrigger>
            <TabsTrigger value="addresses">Addresses</TabsTrigger>
            <TabsTrigger value="family">Family</TabsTrigger>
          </TabsList>

          {/* PERSONAL INFO */}
          <TabsContent value="personal" className="space-y-4">
            {/* Avatar card */}
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
              <Card>
                <CardContent className="p-6">
                  <div className="flex flex-col sm:flex-row items-center gap-6">
                    <div className="relative">
                      <Avatar className="h-24 w-24 ring-4 ring-background shadow-md">
                        <AvatarImage src={user?.avatar} alt={user?.name ?? 'User avatar'} />
                        <AvatarFallback className="text-2xl gradient-primary text-primary-foreground">
                          {getInitials(user?.name || 'MS')}
                        </AvatarFallback>
                      </Avatar>
                      <button
                        className="absolute bottom-0 right-0 h-8 w-8 bg-primary text-primary-foreground rounded-full flex items-center justify-center shadow-md hover:bg-primary/90 transition-colors"
                        onClick={() => toast({ title: 'Upload photo', description: 'Photo upload coming soon.' })}
                        aria-label="Change photo"
                      >
                        <Camera className="h-4 w-4" />
                      </button>
                    </div>
                    <div className="text-center sm:text-left">
                      <h2 className="text-xl font-bold text-foreground">{profile.name}</h2>
                      <p className="text-muted-foreground text-sm">{profile.email}</p>
                      <div className="flex flex-wrap justify-center sm:justify-start gap-2 mt-2">
                        <Badge variant="secondary">Patient</Badge>
                        {profile.hmoProvider && <Badge className="bg-primary/10 text-primary border-primary/20">HMO: {profile.hmoProvider.split('/')[0].trim()}</Badge>}
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </motion.div>

            {/* Personal details */}
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.05 }}>
              <Card>
                <CardHeader className="flex flex-row items-center justify-between pb-3">
                  <CardTitle className="text-base flex items-center gap-2">
                    <User className="h-4 w-4 text-primary" /> Personal Information
                  </CardTitle>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="gap-1.5 h-8"
                    onClick={() => setEditingSection(editingSection === 'personal' ? null : 'personal')}
                  >
                    {editingSection === 'personal' ? <><X className="h-3.5 w-3.5" /> Cancel</> : <><Edit2 className="h-3.5 w-3.5" /> Edit</>}
                  </Button>
                </CardHeader>
                <CardContent className="space-y-4">
                  {editingSection === 'personal' ? (
                    <>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <Label>Full Name</Label>
                          <Input value={profile.name} onChange={(e) => setProfile({ ...profile, name: e.target.value })} />
                        </div>
                        <div className="space-y-1.5">
                          <Label>Phone Number</Label>
                          <Input value={profile.phone} onChange={(e) => setProfile({ ...profile, phone: e.target.value })} />
                        </div>
                        <div className="space-y-1.5">
                          <Label>Date of Birth</Label>
                          <Input type="date" value={profile.dob} onChange={(e) => setProfile({ ...profile, dob: e.target.value })} />
                        </div>
                        <div className="space-y-1.5">
                          <Label htmlFor="profile-gender">Gender</Label>
                          <select
                            id="profile-gender"
                            aria-label="Gender"
                            className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                            value={profile.gender}
                            onChange={(e) => setProfile({ ...profile, gender: e.target.value })}
                          >
                            <option value="female">Female</option>
                            <option value="male">Male</option>
                            <option value="other">Other</option>
                          </select>
                        </div>
                        <div className="space-y-1.5">
                          <Label>Emergency Contact Name</Label>
                          <Input value={profile.emergencyName} onChange={(e) => setProfile({ ...profile, emergencyName: e.target.value })} />
                        </div>
                        <div className="space-y-1.5">
                          <Label>Emergency Contact Number</Label>
                          <Input value={profile.emergencyContact} onChange={(e) => setProfile({ ...profile, emergencyContact: e.target.value })} />
                        </div>
                      </div>
                      <Button onClick={() => handleSave('Personal information')} className="gap-2">
                        <Save className="h-4 w-4" /> Save Changes
                      </Button>
                    </>
                  ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      {[
                        { label: 'Full Name', value: profile.name, icon: User },
                        { label: 'Phone', value: profile.phone, icon: Phone },
                        { label: 'Email', value: profile.email, icon: Mail },
                        { label: 'Date of Birth', value: profile.dob, icon: Calendar },
                        { label: 'Gender', value: profile.gender.charAt(0).toUpperCase() + profile.gender.slice(1), icon: User },
                        { label: 'Emergency Contact', value: `${profile.emergencyName} · ${profile.emergencyContact}`, icon: Phone },
                      ].map(({ label, value, icon: Icon }) => (
                        <div key={label} className="flex items-start gap-3">
                          <div className="p-2 bg-secondary rounded-lg shrink-0">
                            <Icon className="h-4 w-4 text-primary" />
                          </div>
                          <div>
                            <p className="text-xs text-muted-foreground">{label}</p>
                            <p className="text-sm font-medium text-foreground">{value}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </CardContent>
              </Card>
            </motion.div>

            {/* HMO */}
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}>
              <Card>
                <CardHeader className="flex flex-row items-center justify-between pb-3">
                  <CardTitle className="text-base flex items-center gap-2">
                    <Shield className="h-4 w-4 text-primary" /> HMO / Health Insurance
                  </CardTitle>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="gap-1.5 h-8"
                    onClick={() => setEditingSection(editingSection === 'hmo' ? null : 'hmo')}
                  >
                    {editingSection === 'hmo' ? <><X className="h-3.5 w-3.5" /> Cancel</> : <><Edit2 className="h-3.5 w-3.5" /> Edit</>}
                  </Button>
                </CardHeader>
                <CardContent>
                  {editingSection === 'hmo' ? (
                    <div className="space-y-4">
                      <div className="space-y-1.5">
                        <Label>HMO Provider</Label>
                        <Input value={profile.hmoProvider} onChange={(e) => setProfile({ ...profile, hmoProvider: e.target.value })} />
                      </div>
                      <div className="space-y-1.5">
                        <Label>HMO Member Number</Label>
                        <Input value={profile.hmoNumber} onChange={(e) => setProfile({ ...profile, hmoNumber: e.target.value })} placeholder="e.g. MXC-2024-001234" />
                      </div>
                      <Button onClick={() => handleSave('HMO details')} className="gap-2">
                        <Save className="h-4 w-4" /> Save Changes
                      </Button>
                    </div>
                  ) : (
                    <div className="space-y-3">
                      <div className="p-4 bg-primary/5 border border-primary/20 rounded-xl">
                        <div className="flex items-start justify-between">
                          <div>
                            <p className="font-semibold text-foreground">{profile.hmoProvider}</p>
                            <p className="text-sm text-muted-foreground mt-0.5">Member No: <span className="font-mono">{profile.hmoNumber}</span></p>
                          </div>
                          <CheckCircle className="h-5 w-5 text-success" />
                        </div>
                      </div>
                      <p className="text-xs text-muted-foreground flex items-center gap-1.5">
                        <Lock className="h-3 w-3" /> Your HMO details are used to check coverage with partner doctors.
                      </p>
                    </div>
                  )}
                </CardContent>
              </Card>
            </motion.div>
          </TabsContent>

          {/* HEALTH INFO */}
          <TabsContent value="health" className="space-y-4">
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
              <Card>
                <CardHeader className="flex flex-row items-center justify-between pb-3">
                  <CardTitle className="text-base flex items-center gap-2">
                    <Heart className="h-4 w-4 text-primary" /> Health Information
                  </CardTitle>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="gap-1.5 h-8"
                    onClick={() => setEditingSection(editingSection === 'health' ? null : 'health')}
                  >
                    {editingSection === 'health' ? <><X className="h-3.5 w-3.5" /> Cancel</> : <><Edit2 className="h-3.5 w-3.5" /> Edit</>}
                  </Button>
                </CardHeader>
                <CardContent className="space-y-5">
                  {editingSection === 'health' ? (
                    <div className="space-y-4">
                      <div className="space-y-1.5">
                        <Label htmlFor="profile-blood-type">Blood Type</Label>
                        <select
                          id="profile-blood-type"
                          aria-label="Blood type"
                          className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                          value={profile.bloodType}
                          onChange={(e) => setProfile({ ...profile, bloodType: e.target.value })}
                        >
                          {bloodTypes.map((bt) => <option key={bt} value={bt}>{bt}</option>)}
                        </select>
                      </div>
                      <div className="space-y-1.5">
                        <Label>Known Allergies (comma-separated)</Label>
                        <Input value={profile.allergies} onChange={(e) => setProfile({ ...profile, allergies: e.target.value })} placeholder="e.g. Penicillin, Sulfa" />
                      </div>
                      <Button onClick={() => handleSave('Health information')} className="gap-2">
                        <Save className="h-4 w-4" /> Save Changes
                      </Button>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div className="p-4 bg-destructive/5 border border-destructive/20 rounded-xl">
                        <div className="flex items-center gap-3">
                          <Droplets className="h-8 w-8 text-destructive" />
                          <div>
                            <p className="text-xs text-muted-foreground">Blood Type</p>
                            <p className="text-2xl font-bold text-foreground">{profile.bloodType}</p>
                          </div>
                        </div>
                      </div>
                      <div className="p-4 bg-warning/5 border border-warning/20 rounded-xl">
                        <div className="flex items-start gap-3">
                          <AlertTriangle className="h-5 w-5 text-warning mt-0.5 shrink-0" />
                          <div>
                            <p className="text-xs text-muted-foreground">Known Allergies</p>
                            <div className="flex flex-wrap gap-1 mt-1">
                              {allergyList.length === 0 ? (
                                <Badge className="bg-muted text-muted-foreground border-muted text-xs">None reported</Badge>
                              ) : (
                                allergyList.map((a, index) => (
                                  <Badge key={`${a}-${index}`} className="bg-warning/20 text-warning-foreground border-warning/30 text-xs">
                                    {a}
                                  </Badge>
                                ))
                              )}
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  )}

                  <div className="p-3 bg-secondary/50 rounded-xl">
                    <p className="text-xs text-muted-foreground flex items-center gap-1.5">
                      <Lock className="h-3 w-3" /> Health data is encrypted and shared only with your consulting doctors.
                    </p>
                  </div>
                </CardContent>
              </Card>
            </motion.div>
          </TabsContent>

          {/* ADDRESSES */}
          <TabsContent value="addresses" className="space-y-4">
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
              <div className="flex items-center justify-between mb-2">
                <h3 className="font-semibold text-foreground">Saved Delivery Addresses</h3>
                <Button size="sm" className="gap-1.5" onClick={() => setAddAddressOpen(true)}>
                  <Plus className="h-4 w-4" /> Add Address
                </Button>
              </div>
              <div className="space-y-3">
                {savedAddresses.map((addr) => (
                  <Card key={addr.id}>
                    <CardContent className="p-4">
                      <div className="flex items-start gap-3">
                        <div className="p-2 bg-primary/10 rounded-lg">
                          <MapPin className="h-4 w-4 text-primary" />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-0.5">
                            <p className="font-medium text-sm text-foreground">{addr.fullName}</p>
                            {addr.isDefault && <Badge className="bg-primary/10 text-primary border-primary/20 text-xs">Default</Badge>}
                          </div>
                          <p className="text-xs text-muted-foreground">{addr.mobile}</p>
                          <p className="text-sm text-muted-foreground mt-1">
                            {addr.houseUnit} {addr.street}, Brgy. {addr.barangay}, {addr.city}, {addr.province} {addr.zipCode}
                          </p>
                          {addr.notes && <p className="text-xs italic text-muted-foreground mt-0.5">{addr.notes}</p>}
                        </div>
                        <Button variant="ghost" size="icon" className="text-muted-foreground hover:text-destructive h-8 w-8">
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </motion.div>
          </TabsContent>

          {/* FAMILY MEMBERS */}
          <TabsContent value="family" className="space-y-4">
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
              <div className="flex items-center justify-between mb-2">
                <h3 className="font-semibold text-foreground">Family Members</h3>
                <Button size="sm" className="gap-1.5" onClick={() => setAddFamilyOpen(true)}>
                  <Plus className="h-4 w-4" /> Add Member
                </Button>
              </div>
              <div className="space-y-3">
                {familyMembers.map((fm) => (
                  <Card key={fm.id}>
                    <CardContent className="p-4">
                      <div className="flex items-center gap-4">
                        <Avatar className="h-10 w-10">
                          <AvatarFallback className="bg-secondary text-secondary-foreground text-sm">
                            {fm.name.split(' ').map((n) => n[0]).join('')}
                          </AvatarFallback>
                        </Avatar>
                        <div className="flex-1">
                          <p className="font-medium text-sm text-foreground">{fm.name}</p>
                          <p className="text-xs text-muted-foreground">{fm.relationship} · DOB: {fm.dob} · Blood: {fm.bloodType}</p>
                        </div>
                        <Button variant="ghost" size="icon" className="h-8 w-8">
                          <Edit2 className="h-4 w-4 text-muted-foreground" />
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
              <p className="text-xs text-muted-foreground text-center">Family members can be selected when booking appointments for dependents.</p>
            </motion.div>
          </TabsContent>
        </Tabs>

        {/* Add Address Dialog */}
        <Dialog open={addAddressOpen} onOpenChange={setAddAddressOpen}>
          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle>Add Delivery Address</DialogTitle>
            </DialogHeader>
            <div className="space-y-3 max-h-96 overflow-y-auto pr-1">
              {addressFields.map(({ label, key, placeholder }) => (
                <div key={key} className="space-y-1">
                  <Label className="text-xs">{label}</Label>
                  <Input
                    placeholder={placeholder}
                    value={newAddress[key] ?? ''}
                    onChange={(e) => setNewAddress({ ...newAddress, [key]: e.target.value })}
                  />
                </div>
              ))}
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setAddAddressOpen(false)}>Cancel</Button>
              <Button onClick={handleAddAddress} className="gap-2">
                <Plus className="h-4 w-4" /> Save Address
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        {/* Add Family Member Dialog */}
        <Dialog open={addFamilyOpen} onOpenChange={setAddFamilyOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Add Family Member</DialogTitle>
            </DialogHeader>
            <div className="space-y-3">
              <div className="space-y-1.5"><Label>Full Name</Label><Input placeholder="Juan Santos" /></div>
              <div className="space-y-1.5"><Label>Relationship</Label><Input placeholder="e.g. Child, Spouse, Parent" /></div>
              <div className="space-y-1.5"><Label>Date of Birth</Label><Input type="date" /></div>
              <div className="space-y-1.5">
                <Label htmlFor="family-blood-type">Blood Type</Label>
                <select
                  id="family-blood-type"
                  aria-label="Family member blood type"
                  className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                >
                  {bloodTypes.map((bt) => <option key={bt} value={bt}>{bt}</option>)}
                </select>
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setAddFamilyOpen(false)}>Cancel</Button>
              <Button onClick={() => { toast({ title: 'Family member added!' }); setAddFamilyOpen(false); }} className="gap-2">
                <Users className="h-4 w-4" /> Add Member
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </DashboardLayout>
  );
}
